#include <stdio.h>
#include <string.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char S[100005];
        scanf("%s", S);
        int i, count = 1;
        char prev = S[0];
        char good = (prev == 'f' || prev == 'r' || prev == 'i' || prev == 'e' || prev == 'z' || prev == 'a');
        for (i = 1; S[i]; i++) {
            if ((S[i] == 'f' || S[i] == 'r' || S[i] == 'i' || S[i] == 'e' || S[i] == 'z' || S[i] == 'a') == good) {
                count++;
            } else {
                printf("%d", count);
                count = 1;
                good = (S[i] == 'f' || S[i] == 'r' || S[i] == 'i' || S[i] == 'e' || S[i] == 'z' || S[i] == 'a');
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

