import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            String S = sc.next();
            int i, count = 1;
            char prev = S.charAt(0);
            boolean good = (prev == 'f' || prev == 'r' || prev == 'i' || prev == 'e' || prev == 'z' || prev == 'a');
            for (i = 1; i < S.length(); i++) {
                if ((S.charAt(i) == 'f' || S.charAt(i) == 'r' || S.charAt(i) == 'i' || S.charAt(i) == 'e' || S.charAt(i) == 'z' || S.charAt(i) == 'a') == good) {
                    count++;
                } else {
                    System.out.print(count);
                    count = 1;
                    good = (S.charAt(i) == 'f' || S.charAt(i) == 'r' || S.charAt(i) == 'i' || S.charAt(i) == 'e' || S.charAt(i) == 'z' || S.charAt(i) == 'a');
                }
            }
            System.out.println(count);
